function speak(text, lang) {
    if (typeof stopVoiceRecognitionTemporarily === 'function') {
        stopVoiceRecognitionTemporarily();
    }

    synth.cancel(); 

    if (lang === 'ko-KR') {
        koTextDisplay.classList.remove('hidden-text');
    } else {
        enTextDisplay.classList.remove('hidden-text');
    }

    setTimeout(() => {
        const cleanedText = cleanTextForSpeech(text);
        if (!cleanedText) {
            if (typeof resumeVoiceRecognition === 'function') {
                resumeVoiceRecognition();
            }
            return;
        }

        const utterance = new SpeechSynthesisUtterance(cleanedText);
        utterance.lang = lang;

        if (lang === 'ko-KR') {
            utterance.rate = parseFloat(koSpeedInput.value);
        } else {
            utterance.rate = parseFloat(enSpeedInput.value);
        }

        currentUtterance = utterance;

        // ==========[여기부터 수정된 부분]==========
        utterance.onend = () => {
            currentUtterance = null;

            // TTS 재생이 끝났으므로, STT가 사용자 명령을 들을 수 있도록 먼저 무시 모드를 해제합니다.
            if (typeof resumeVoiceRecognition === 'function') {
                resumeVoiceRecognition();
            }

            const isRepeating = (infiniteRepeatMode !== null) || repeatCheckbox.checked;

            if (isRepeating) {
                 // 음성 명령(STT)으로 인한 무한 반복일 경우, 3초 후 다시 speak 함수를 호출합니다.
                 if ((infiniteRepeatMode === 'ko' && lang === 'ko-KR') || (infiniteRepeatMode === 'en' && lang === 'en-US')) {
                    console.log("🔁 3초 후 반복 (이제 음성 명령 가능)");
                    // 3초 대기 후 speak()를 호출합니다. speak()는 시작 시점에 다시 STT 무시 모드를 설정합니다.
                    setTimeout(() => speak(text, lang), 3000);
                } else if (repeatCheckbox.checked) { 
                    // 체크박스를 통한 반복은 지연 없이 바로 다시 재생을 시작합니다.
                    speak(text, lang);
                }
            }
        };
        // ==========[여기까지 수정된 부분]==========

        synth.speak(utterance);
    }, 50); 
}

